patch:
--- a/decoder_priority.vhd
+++ b/decoder_priority.vhd
@@ -1,17 +1,17 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity decoder_priority is
   port (
     sel : in std_logic_vector(2 downto 0);
     input_vec : in std_logic_vector(7 downto 0);
     output : out std_logic
   );
 end entity decoder_priority;

 architecture rtl of decoder_priority is
 begin
-  process(sel)
+  process(sel, input_vec)
   begin
     case sel is
       when "000" => output <= input_vec(0);
       when "001" => output <= input_vec(1);
       when "010" => output <= input_vec(2);
       when "011" => output <= input_vec(3);
       when "100" => output <= input_vec(4);
       when "101" => output <= input_vec(5);
       when "110" => output <= input_vec(6);
       when "111" => output <= input_vec(7);
       when others => output <= '0';
     end case;
   end process;
 end architecture rtl;

